  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0007', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Juliette a donné, il y a quelques mois, une procuration à son frère pour administrer ses affaires.  On s’aperçoit maintenant que Juliette n’a plus toute sa tête.  Que doit faire son frère ?', '[{"id": "opt-0", "text": "Continuer à administrer puisqu’il est son mandataire", "isCorrect": true}, {"id": "opt-1", "text": "Appeler le notaire pour être certain que celui-ci émette un mandat d’inaptitude", "isCorrect": false}, {"id": "opt-2", "text": "Cesser d’agir puisque le mandat n’est plus valide", "isCorrect": false}, {"id": "opt-3", "text": "Vendre tous les actifs pour en faire bénéficier Juliette", "isCorrect": false}]'::jsonb, 7, NOW(), NOW())
