  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0010', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Jasmine avait accès à une assurance médicament par l’entremise de l’assurance collective de son conjoint.  Ils ont rompu depuis quelques semaines et elle se demande si elle peut continuer à profiter de cette assurance. Que lui dites-vous ?', '[{"id": "opt-0", "text": "Sans problème, elle a juste à payer sa part.", "isCorrect": true}, {"id": "opt-1", "text": "Oui, si son ex-conjoint y consent et qu’elle paie sa part.", "isCorrect": false}, {"id": "opt-2", "text": "Non, mais de toute façon avoir une assurance médicament n’est pas essentielle.", "isCorrect": false}]'::jsonb, 10, NOW(), NOW())
