  VALUES ('qbi-deontologie_supp-0011', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Jocelyne vient d’avoir 60 ans et même si elle travaille à temps plein, elle a un budget très serré.  Elle se demande si elle peut recevoir sa pension du régime des rentes du Québec.  Que pouvez-vous lui répondre ?', '[{"id": "opt-0", "text": "Non car elle doit avoir 65 ans pour demander son régime de pension.", "isCorrect": true}, {"id": "opt-1", "text": "Non car comme elle a un revenu de travail, elle n’y aura pas accès.", "isCorrect": false}, {"id": "opt-2", "text": "Oui sans problème", "isCorrect": false}, {"id": "opt-3", "text": "Oui mais on diminuera son montant de prestation des revenus qu’elle déclarera.", "isCorrect": false}]'::jsonb, 11, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0012', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'L’application de cette clause signifie que le total des prestations reçues d’une ou des sources de revenus ne doit pas excéder un pourcentage de salaire prévu dans le contrat. S’il y a excédent, il est déduit des prestations versées par l’assureur. Quelle est cette clause ?', '[{"id": "opt-0", "text": "Clause d’intégration", "isCorrect": true}, {"id": "opt-1", "text": "Clause de limitation", "isCorrect": false}, {"id": "opt-2", "text": "Clause de réduction", "isCorrect": false}, {"id": "opt-3", "text": "Clause de pondération", "isCorrect": false}]'::jsonb, 12, NOW(), NOW())
