  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0023', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Sophie a vendu une police d’assurance à Maxime un jeune trisomique de 25 ans. Les parents de Maxime qui ont vu le contrat sur la table ne sont pas content du tout.  Quel vice de consentement peut être invoqué ?', '[{"id": "opt-0", "text": "La crainte", "isCorrect": true}, {"id": "opt-1", "text": "La lésion", "isCorrect": false}, {"id": "opt-2", "text": "L’erreur", "isCorrect": false}, {"id": "opt-3", "text": "La fraude", "isCorrect": false}]'::jsonb, 23, NOW(), NOW())
