  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0029', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Derek, n’a pas ouvert son courrier et du coup il n’a pas payer le renouvellement annuel de son assurance-vie. Par le fait même son assurance est tombée en déchéance.  S’il veut la remettre en force il devra respecter certains critères.  Lequel n’en est pas un ?', '[{"id": "opt-0", "text": "Payer toutes les primes en retard", "isCorrect": true}, {"id": "opt-1", "text": "Faire sa demande dans l’année qui suit la résiliation", "isCorrect": false}, {"id": "opt-2", "text": "Repayer les avances reçues", "isCorrect": false}, {"id": "opt-3", "text": "Répondre aux conditions nécessaires d’assurabilité", "isCorrect": false}]'::jsonb, 29, NOW(), NOW())
