  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0035', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Rebecca a une assurance-vie de 200 000$ qu’elle a prise il y a 5 ans. Le mois dernier, suite à la naissance de son premier enfant, elle a augmenté son assurance de 100 000$. Hier, dans un moment de désespoir, elle s’est suicidée.  Combien sa succession recevra-t-elle ?', '[{"id": "opt-0", "text": "200 000$", "isCorrect": true}, {"id": "opt-1", "text": "0$ car elle s’est suicidée", "isCorrect": false}, {"id": "opt-2", "text": "300 000$", "isCorrect": false}, {"id": "opt-3", "text": "100 000$", "isCorrect": false}]'::jsonb, 35, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0036', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Lors d’une modification au contrat par l’assureur, celle-ci est présumée accepté par le preneur :', '[{"id": "opt-0", "text": "10 jours après réception du document", "isCorrect": true}, {"id": "opt-1", "text": "30 jours après réception du document", "isCorrect": false}, {"id": "opt-2", "text": "60 jours après réception du document", "isCorrect": false}, {"id": "opt-3", "text": "90 jours après réception du document", "isCorrect": false}]'::jsonb, 36, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0037', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Jean-David a pris une assurance vie et a désigné sa succession comme bénéficiaire.  Au moment de son décès il doit beaucoup d’argent à ses créanciers.  Qui recevra l’argent de son assurance?', '[{"id": "opt-0", "text": "Sa succession tel qu’indiqué au contrat", "isCorrect": true}, {"id": "opt-1", "text": "Sa succession à 50% et ses créanciers pour l’autre 50%", "isCorrect": false}]'::jsonb, 37, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0038', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Y-a-t-il une façon de retirer un bénéficiaire irrévocable d’un contrat sans son consentement ?', '[{"id": "opt-0", "text": "Oui, car le propriétaire de la police à tous les droits", "isCorrect": true}, {"id": "opt-1", "text": "Jamais car pour un bénéficiaire irrévocable ça prend toujours un consentement", "isCorrect": false}, {"id": "opt-2", "text": "Oui, en cédant la police à un nouveau titulaire", "isCorrect": false}, {"id": "opt-3", "text": "Oui, dans le cas d’un divorce si la police a été prise durant le mariage", "isCorrect": false}]'::jsonb, 38, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0039', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Joseph est un représentant en assurance qui est très consciencieux.  Il est par le fait même très proche de ses clients.  Lors de sa dernière visite chez Mme Tanguay, celle-ci lui a déclaré vouloir le mettre comme bénéficiaire sur sa police d’assurance puisqu’ils se connaissent depuis plus de 30 ans.  Joseph peut-il être son bénéficiaire ?', '[{"id": "opt-0", "text": "Oui, sans problème", "isCorrect": true}, {"id": "opt-1", "text": "Oui, mais il devra signer un document concernant les conflits d’intérêts", "isCorrect": false}, {"id": "opt-2", "text": "Oui, avec le consentement de ses enfants", "isCorrect": false}, {"id": "opt-3", "text": "Non, car il est en conflit d’intérêt", "isCorrect": false}]'::jsonb, 39, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0040', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Laquelle des façons suivantes n’est pas un mode de désignation de bénéficiaire au Québec ?', '[{"id": "opt-0", "text": "Dans un écrit fait à la main", "isCorrect": true}, {"id": "opt-1", "text": "Dans un testament", "isCorrect": false}, {"id": "opt-2", "text": "En demandant à son agent de faire la modification de bénéficiaire", "isCorrect": false}, {"id": "opt-3", "text": "De façon électronique", "isCorrect": false}]'::jsonb, 40, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0041', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Oui, le syndic peut demander à l’assureur de lui verser une partie de la prestation.', '[{"id": "opt-0", "text": "Non, les montants sont insaisissables par la loi.", "isCorrect": true}, {"id": "opt-1", "text": "Non, car l’assuré a déjà des problèmes financiers.", "isCorrect": false}]'::jsonb, 41, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0042', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Qu’est-ce qui n’est pas considéré comme une preuve de décès ?', '[{"id": "opt-0", "text": "Une copie de la nécrologie du journal local mentionnant le décès", "isCorrect": true}, {"id": "opt-1", "text": "Certificat de décès", "isCorrect": false}, {"id": "opt-2", "text": "Copie de l’acte de décès", "isCorrect": false}, {"id": "opt-3", "text": "Déclaration de décès signée par un directeur de funérailles", "isCorrect": false}]'::jsonb, 42, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0043', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Combien de temps le bénéficiaire d’une assurance vie a-t-il pour faire valoir ses droits à l’assureur ?', '[{"id": "opt-0", "text": "30 jours", "isCorrect": true}, {"id": "opt-1", "text": "90 jours", "isCorrect": false}, {"id": "opt-2", "text": "2 ans", "isCorrect": false}, {"id": "opt-3", "text": "3 ans", "isCorrect": false}]'::jsonb, 43, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0044', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Lors de l’hospitalisation de la petite Clara, 8 ans, la DPJ a saisi le dossier et celle-ci a été confiée à une famille d’accueil.  Bien entendu les parents n’ont jamais cessé de payer la prime.  Qui aura droit à la prestation ?', '[{"id": "opt-0", "text": "Les parents car ce sont eux qui paient la prime", "isCorrect": true}, {"id": "opt-1", "text": "Clara car la police est à son nom", "isCorrect": false}, {"id": "opt-2", "text": "Le directeur de la DPJ", "isCorrect": false}]'::jsonb, 44, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0045', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'En assurance collective, quel est le document constatant le contrat et devant contenir les indications et mentions prescrites par le législateur ?', '[{"id": "opt-0", "text": "Une attestation d’assurance", "isCorrect": true}, {"id": "opt-1", "text": "Le contrat cadre", "isCorrect": false}, {"id": "opt-2", "text": "Le contrat d’assurance remis aux adhérents", "isCorrect": false}, {"id": "opt-3", "text": "La dernière contre-proposition", "isCorrect": false}]'::jsonb, 45, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0046', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Claudine a subi une fracture. Son assurance collective lui verse 1500$ par mois.  De plus, lors de son premier versement elle reçoit un montant forfaitaire de 1000$ supplémentaire.  Surprise, elle consulte sa brochure et s’aperçoit qu’elle aurait dû recevoir 2000$ pour une fracture. Elle appelle son employeur qui vérifie le contrat cadre dans lequel il est inscrit qu’elle ne devrait recevoir que 1000$.  Elle croit avoir droit au 2000$ puisque c’est dans sa brochure.  Selon vous a-t-elle raison ?', '[{"id": "opt-0", "text": "Non, la compagnie paie toujours le moindre des deux montants", "isCorrect": true}, {"id": "opt-1", "text": "Non, car le contrat cadre est toujours celui qui domine", "isCorrect": false}, {"id": "opt-2", "text": "Oui, car la brochure est toujours celle qui domine", "isCorrect": false}]'::jsonb, 46, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0047', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Mika est en invalidité depuis maintenant 24 mois et vient de se voir offrir un emploi en administration par son employeur vu qu’elle ne retournera pas à son poste habituel.  Mika ne voulant pas faire de travaux administratifs se demande ce qu’elle peut faire.  Peut-elle demeurer sur son assurance invalidité collective?', '[{"id": "opt-0", "text": "Oui, jusqu’à ce que l’employeur lui trouve un poste qui lui convient.", "isCorrect": true}, {"id": "opt-1", "text": "Oui, jusqu’à ce qu’elle puisse retourner à son poste habituel.", "isCorrect": false}, {"id": "opt-2", "text": "Oui, car l’employeur doit toujours offrir plusieurs alternatives.", "isCorrect": false}, {"id": "opt-3", "text": "Non, si l’employeur lui offre une solution adaptée, elle doit l’accepter.", "isCorrect": false}]'::jsonb, 47, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0048', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'La liste obligatoire des médicaments couvert par l’assurance médicament au Québec doit être de :', '[{"id": "opt-0", "text": "6000 médicaments couvert à 63%", "isCorrect": true}, {"id": "opt-1", "text": "6000 médicaments couvert à 68%", "isCorrect": false}, {"id": "opt-2", "text": "8000 médicaments couvert à 68%", "isCorrect": false}, {"id": "opt-3", "text": "8000 médicaments couvert à 63%", "isCorrect": false}]'::jsonb, 48, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0049', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Lorsqu’on contracte une assurance-prêt, on sait que le prêteur est le bénéficiaire, qui est le preneur ?', '[{"id": "opt-0", "text": "Le client", "isCorrect": true}, {"id": "opt-1", "text": "L’institution financière", "isCorrect": false}, {"id": "opt-2", "text": "L’assureur", "isCorrect": false}, {"id": "opt-3", "text": "Personne, puisqu’en assurance-prêt il n’y a pas de preneur", "isCorrect": false}]'::jsonb, 49, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0050', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'En assurance collective, la preuve d’assurabilité des adhérents se limite en général à une seule chose, laquelle ?', '[{"id": "opt-0", "text": "À être présent au travail lors de la prise d’effet de la police", "isCorrect": true}, {"id": "opt-1", "text": "À un questionnaire médical", "isCorrect": false}, {"id": "opt-2", "text": "À une entrevue faite lors de la proposition", "isCorrect": false}, {"id": "opt-3", "text": "À la bonne foi", "isCorrect": false}]'::jsonb, 50, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0051', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Cynthia est employée dans une entreprise où l’assurance collective est obligatoire.  Elle est déjà couverte par l’assurance collective de son conjoint.  Que peut elle faire ?', '[{"id": "opt-0", "text": "Elle peut expliquer la situation et ne pas s’inscrire.", "isCorrect": true}, {"id": "opt-1", "text": "Elle devra prendre la couverture telle qu’offerte puisque c’est obligatoire.", "isCorrect": false}]'::jsonb, 51, NOW(), NOW())
  ON CONFLICT DO NOTHING;
