  VALUES ('qbi-deontologie_supp-0052', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Dans le cadre de l’assurance-médicament on défini un conjoint selon certain critère.  Lequel n’en est pas un ?', '[{"id": "opt-0", "text": "Être marié ou uni civilement", "isCorrect": true}, {"id": "opt-1", "text": "Vivre maritalement depuis au moins 3 ans", "isCorrect": false}, {"id": "opt-2", "text": "Vivre maritalement depuis 12 mois", "isCorrect": false}, {"id": "opt-3", "text": "Vivre maritalement et avoir un enfant ensemble", "isCorrect": false}]'::jsonb, 52, NOW(), NOW())
