  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0053', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Jonathan a 23 ans et habite encore chez ses parents.  Il travaille à temps plein dans une boulangerie qui n’offre pas d’assurance collective.  Il se demande s’il est encore couvert par celle de ses parents. Que lui répondez-vous ?', '[{"id": "opt-0", "text": "Oui car tous les enfants sont couverts jusqu’à leurs 25 ans", "isCorrect": true}, {"id": "opt-1", "text": "Oui car il n’y a pas d’âge limite pour les enfants", "isCorrect": false}]'::jsonb, 53, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0054', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Laquelle n’est pas une caractéristique d’une transformation de police d’assurance vie collective en assurance vie individuelle ?', '[{"id": "opt-0", "text": "L’adhérent doit avoir moins de 65 ans", "isCorrect": true}, {"id": "opt-1", "text": "Doit être assuré depuis au moins 5 ans", "isCorrect": false}, {"id": "opt-2", "text": "Pas de qualification médicale si transforme dans les 31 jours suivant l’échéance", "isCorrect": false}, {"id": "opt-3", "text": "Peut transformer pour aussi peu que 5000$ d’assurance vie", "isCorrect": false}]'::jsonb, 54, NOW(), NOW())
  ON CONFLICT DO NOTHING;
