  VALUES ('qbi-deontologie_supp-0056', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Fanny vient d’hériter d’un gros montant d’argent et elle aimerait le placer et ne vivre que des intérêts de ce placement.  Dans quoi devrait-elle le placer ?', '[{"id": "opt-0", "text": "Une rente viagère", "isCorrect": true}, {"id": "opt-1", "text": "Une rente certaine", "isCorrect": false}, {"id": "opt-2", "text": "Une rente à capital fixe", "isCorrect": false}, {"id": "opt-3", "text": "Une rente viagère garantie", "isCorrect": false}]'::jsonb, 56, NOW(), NOW())
