  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0066', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quelle particularité est attribuée au FERR ?', '[{"id": "opt-0", "text": "Le FERR a un montant de retrait minimum annuel imposable.", "isCorrect": true}, {"id": "opt-1", "text": "Le FERR a un montant de retrait minimum et maximum imposable.", "isCorrect": false}, {"id": "opt-2", "text": "Le FERR a un montant de retrait minimum annuel non-imposable.", "isCorrect": false}, {"id": "opt-3", "text": "Le FERR a un montant de retrait minimum et maximum non-imposable.", "isCorrect": false}]'::jsonb, 66, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0067', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Georges, 47 ans, est atteint d’un cancer virulent et il ne lui reste que 8 mois à vivre.  Celui-ci aimerait retirer l’argent de son CRI.  Peut-il le faire?', '[{"id": "opt-0", "text": "Non, car les sommes sont immobilisées.", "isCorrect": true}, {"id": "opt-1", "text": "Oui, comme le REER on peut le retirer quand on veut.", "isCorrect": false}, {"id": "opt-2", "text": "Non, jamais avant l’âge de 65 ans.", "isCorrect": false}]'::jsonb, 67, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0068', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Est-il vrai qu’il faut absolument transformer le CRI en FRV ?', '[{"id": "opt-0", "text": "Oui, c’est la règle", "isCorrect": true}, {"id": "opt-1", "text": "Non, on peut le transformer en FERR", "isCorrect": false}, {"id": "opt-2", "text": "Non, on peut aussi le transformer en rente viagère", "isCorrect": false}, {"id": "opt-3", "text": "Non, on peut aussi le transformer en rente certaine", "isCorrect": false}]'::jsonb, 68, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0069', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Réal, 65 ans, voudrait faire le tour du monde pendant qu’il est encore en bonne santé.  Il voudrait donc sortir l’argent de son CRI.  Il a cumulé dans celui-ci 42500$.  Peut-il le faire ?', '[{"id": "opt-0", "text": "Oui, car il a plus de 65 ans.", "isCorrect": true}, {"id": "opt-1", "text": "Oui, mais il devra payer un gros montant d’impôt.", "isCorrect": false}, {"id": "opt-2", "text": "Non, car la somme est plus élevée que 40% du MGA qui s’établit à 57400$", "isCorrect": false}, {"id": "opt-3", "text": "Non, car les sommes doivent rester non-immobilisées.", "isCorrect": false}]'::jsonb, 69, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0070', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Johnny, 70 ans, vient d’apprendre qu’il est atteint de la sclérose latérale amyotrophique alors son temps est compté.  Il a toujours voulu voir le Grand Canyon et voudrait sortir l’argent de son FRV.  Est-ce possible pour Johnny ?', '[{"id": "opt-0", "text": "Oui, s’il transfert son FRV dans un CRI puisqu’il a encore l’âge pour le faire.", "isCorrect": true}, {"id": "opt-1", "text": "Oui, car l’invalidité physique est une exception pour sortir du FRV.", "isCorrect": false}, {"id": "opt-2", "text": "Non, il est trop tard car il est en phase de service.", "isCorrect": false}, {"id": "opt-3", "text": "Non, de toute façon il n’a plus la santé pour aller voir le Grand Canyon.", "isCorrect": false}]'::jsonb, 70, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0071', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Nathalie, qui vient d’hériter d’un gros montant, voudrait cotiser à un CELI mais elle ne sait pas le montant qu’elle peut y déposer.  Si vous savez que Nathalie a aujourd’hui 45 ans et qu’on est le 31 décembre 2019, quel est le montant maximum qu’elle peut déposer ?', '[{"id": "opt-0", "text": "5500$", "isCorrect": true}, {"id": "opt-1", "text": "6000$", "isCorrect": false}, {"id": "opt-2", "text": "72500$", "isCorrect": false}, {"id": "opt-3", "text": "63500$", "isCorrect": false}]'::jsonb, 71, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0072', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Dans une entente pour une rente collective, l’assureur peut offrir plusieurs services.  Lequel n’en est pas un ?', '[{"id": "opt-0", "text": "Rédiger les brochures explicatives destinées aux participants", "isCorrect": true}, {"id": "opt-1", "text": "Tenir des séances d’information pour les participants", "isCorrect": false}, {"id": "opt-2", "text": "Fournir des outils relatifs à l’évolution des fonds offerts", "isCorrect": false}, {"id": "opt-3", "text": "Offrir les services de conseillers juridiques", "isCorrect": false}]'::jsonb, 72, NOW(), NOW())
  ON CONFLICT DO NOTHING;
