  VALUES ('qbi-deontologie_supp-0073', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Angela est policière dans les forces armées.  Son employeur lui dit toujours qu’à sa retraite elle recevra un pourcentage de ses 5 meilleures années de salaire.  Son régime est donc :', '[{"id": "opt-0", "text": "À cotisation déterminée", "isCorrect": true}, {"id": "opt-1", "text": "À prestation déterminée", "isCorrect": false}, {"id": "opt-2", "text": "À deux volets", "isCorrect": false}, {"id": "opt-3", "text": "À prestation anticipée", "isCorrect": false}]'::jsonb, 73, NOW(), NOW())
