  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0099', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'La Loi de l’impôt sur le revenu qui régit le RPDB l’oblige à être en fiducie auprès d’une société de fiducie ou d’au moins :', '[{"id": "opt-0", "text": "1 fiduciaire", "isCorrect": true}, {"id": "opt-1", "text": "2 fiduciaires", "isCorrect": false}, {"id": "opt-2", "text": "3 fiduciaires", "isCorrect": false}, {"id": "opt-3", "text": "4 fiduciaires", "isCorrect": false}]'::jsonb, 99, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0100', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Certains employeurs permettent aux employés de participer à la croissance de leur entreprise en versant des sommes dans un régime. Celui-ci est alors dit « non enregistré », et les sommes ne s’accumulent pas en franchise d’impôt. L’employeur verse parfois des cotisations complémentaires égales à un pourcentage des cotisations de l’employé.  Comment appelle-t-on ce régime ?', '[{"id": "opt-0", "text": "Un RPDB", "isCorrect": true}, {"id": "opt-1", "text": "Un REER collectif", "isCorrect": false}, {"id": "opt-2", "text": "Un RPEB", "isCorrect": false}, {"id": "opt-3", "text": "Un RPA", "isCorrect": false}]'::jsonb, 100, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0101', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Sa succession mais si celle-ci est déficitaire elle pourrait réclamer la part des impôts à Jonas', '[{"id": "opt-0", "text": "Il n’y a pas d’impôt à payer puisqu’il sera transféré dans les REER de Jonas", "isCorrect": true}, {"id": "opt-1", "text": "Sa succession parce que Jonas n’avait pas le droit d’être bénéficiaire", "isCorrect": false}]'::jsonb, 101, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0102', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Cassy avait désigné comme bénéficiaire de son régime de retraite, Brandon son fils.  Lors de son décès dû à un accident de travail, Cassy avait 45 ans. Sachant qu’elle avait une relation maritale avec Jordan depuis 5 ans et n’avait pas fait de changement de bénéficiaire, qui recevra les droits accumulés du régime de retraite ?', '[{"id": "opt-0", "text": "La succession", "isCorrect": true}, {"id": "opt-1", "text": "Brandon", "isCorrect": false}, {"id": "opt-2", "text": "Jordan", "isCorrect": false}, {"id": "opt-3", "text": "Brandon et Jordan se partageront 50% chacun dû au patrimoine familial", "isCorrect": false}]'::jsonb, 102, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-deontologie_supp-0103', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Éric travaille depuis 30 ans pour la compagnie ABC.  Lorsqu’on lui avait demandé de nommer un bénéficiaire pour son régime de pension, il avait nommé Natacha, sa meilleure amie.  Dans les années qui suivirent Natacha et Éric ont vécu maritalement pendant plus de 20 ans.  Il y a deux ans, ils ont rompu et depuis, Éric vit maritalement avec Suzy.  Il se demande qui recevrait les droits accumulés dans son régime de retraite, s’il venait à décéder subitement.  Que lui répondez-vous ?', '[{"id": "opt-0", "text": "La succession", "isCorrect": true}, {"id": "opt-1", "text": "Natacha", "isCorrect": false}, {"id": "opt-2", "text": "Suzy", "isCorrect": false}, {"id": "opt-3", "text": "Les parents d’Éric", "isCorrect": false}]'::jsonb, 103, NOW(), NOW())
  ON CONFLICT DO NOTHING;
