  VALUES ('qbi-deontologie_supp-0104', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Marcel a divorcé, il y a 10 ans, alors qu’il débutait sa phase de service.  Il avait fait réajuster sa rente suite à son divorce. Depuis, il vit avec Suzanne.  S’il décédait demain, qui recevrait sa rente ?', '[{"id": "opt-0", "text": "La succession", "isCorrect": true}, {"id": "opt-1", "text": "Suzanne", "isCorrect": false}, {"id": "opt-2", "text": "Son ex-épouse", "isCorrect": false}, {"id": "opt-3", "text": "Personne puisque la réversibilité ne s’appliquerait pas", "isCorrect": false}]'::jsonb, 104, NOW(), NOW())
  ON CONFLICT DO NOTHING;
