  VALUES ('qbi-deontologie_supp-0106', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'François et Monique sont passé à l’évaluation de leur patrimoine familiale.  Ils doivent se séparer chacun 107 000$.  Si François a 75 000$ dans son régime de retraite, peut-il le verser entièrement à Monique pour ainsi réduire sa dette ?', '[{"id": "opt-0", "text": "Oui, sans problème", "isCorrect": true}, {"id": "opt-1", "text": "Oui, mais seulement si le comité de retraite donne son accord", "isCorrect": false}, {"id": "opt-2", "text": "Non, puisque cet argent est immobilisé", "isCorrect": false}]'::jsonb, 106, NOW(), NOW())
  ON CONFLICT DO NOTHING;
