  VALUES ('qbi-accma_supp-0019', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quelle caractéristique ne s’applique pas à la présomption d’invalidité totale ?', '[{"id": "opt-0", "text": "Peut gagner son plein salaire", "isCorrect": true}, {"id": "opt-1", "text": "Le délai de carence normal ne s’applique pas", "isCorrect": false}, {"id": "opt-2", "text": "N’est pas nécessairement offerte dans toutes les polices", "isCorrect": false}, {"id": "opt-3", "text": "S’applique lorsqu’on perd un ou deux membres", "isCorrect": false}]'::jsonb, 19, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0020', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Sandy vient de perdre sa mère d’une longue invalidité.  Lorsqu’elle regarde le contrat d’assurance invalidité de celle-ci elle s’aperçoit qu’il y a une clause de prestation au survivant.  Elle se demande ce que ça pourrait lui rapporter.  Si vous savez que sa mère recevait 3500$ par mois en invalidité totale, que lui répondez-vous ?', '[{"id": "opt-0", "text": "Elle recevra 3500$ par mois pendant 3 mois", "isCorrect": true}, {"id": "opt-1", "text": "Elle recevra 10500$ dans un montant forfaitaire", "isCorrect": false}, {"id": "opt-2", "text": "Elle recevra 3500$ par mois pendant 4 mois", "isCorrect": false}, {"id": "opt-3", "text": "Elle recevra 14000$ dans un montant forfaitaire", "isCorrect": false}]'::jsonb, 20, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0021', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Dans la prestation au survivant, qu’entend-on par délai d’admissibilité ?', '[{"id": "opt-0", "text": "C’est une période d’invalidité partielle avant le décès", "isCorrect": true}, {"id": "opt-1", "text": "C’est une période d’invalidité résiduelle avant le décès", "isCorrect": false}, {"id": "opt-2", "text": "C’est une période d’invalidité totale avant le décès", "isCorrect": false}, {"id": "opt-3", "text": "C’est une période d’attente avant de recevoir le chèque de l’assureur", "isCorrect": false}]'::jsonb, 21, NOW(), NOW())
  ON CONFLICT DO NOTHING;
