  VALUES ('qbi-accma_supp-0022', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quel facteur n’influence pas les primes en assurance invalidité individuelle ?', '[{"id": "opt-0", "text": "Les frais généraux de fonctionnement", "isCorrect": true}, {"id": "opt-1", "text": "Des tables de morbidité", "isCorrect": false}, {"id": "opt-2", "text": "Une estimation des rendements de placement sur les primes capitalisées", "isCorrect": false}, {"id": "opt-3", "text": "Antécédents de réclamation de la famille de l’assuré", "isCorrect": false}]'::jsonb, 22, NOW(), NOW())
