  VALUES ('qbi-accma_supp-0023', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Qui paiera la prime la plus élevé pour sa police invalidité individuelle ?', '[{"id": "opt-0", "text": "Une femme de 35 ans", "isCorrect": true}, {"id": "opt-1", "text": "Un homme de 35 ans", "isCorrect": false}, {"id": "opt-2", "text": "Une femme de 62 ans", "isCorrect": false}, {"id": "opt-3", "text": "Un homme de 62 ans", "isCorrect": false}]'::jsonb, 23, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0024', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Les assureurs recueillent l’information médicale et l’information relative à la santé pertinentes sur les assurés éventuels grâce à des sources différentes, laquelle n’en est pas une ?', '[{"id": "opt-0", "text": "Formulaire non médical dans la proposition", "isCorrect": true}, {"id": "opt-1", "text": "Déclarations du médecin traitant fournies par le médecin de l’assureur", "isCorrect": false}, {"id": "opt-2", "text": "Examen paramédical d’une infirmière", "isCorrect": false}, {"id": "opt-3", "text": "Examen médical complet d’un médecin", "isCorrect": false}]'::jsonb, 24, NOW(), NOW())
