  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0027', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Sarah a fait une chute à cheval et s’est fracturé la cheville.  Elle a été invalide pendant 5 mois.  Sachant qu’elle a un délai de carence de 3 mois et une période de prestation de 12 mois, combien de temps sera-t-elle exonérée ?', '[{"id": "opt-0", "text": "2 mois", "isCorrect": true}, {"id": "opt-1", "text": "1 mois", "isCorrect": false}, {"id": "opt-2", "text": "5 mois", "isCorrect": false}, {"id": "opt-3", "text": "12 mois", "isCorrect": false}, {"id": "opt-4", "text": "Pour la garantie d’assurabilité future, l’avenant est offert :", "isCorrect": false}, {"id": "opt-5", "text": "À toutes les personnes qui se qualifie d’un point de vue médical", "isCorrect": false}, {"id": "opt-6", "text": "À toutes les personnes qui font moins de 50 000$ par année", "isCorrect": false}, {"id": "opt-7", "text": "À toutes les personnes de la catégories professionnelles 4A", "isCorrect": false}, {"id": "opt-8", "text": "À toutes les personnes de moins de 50 ou 55 ans", "isCorrect": false}]'::jsonb, 27, NOW(), NOW())
