  VALUES ('qbi-accma_supp-0028', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quel avenant accroît de manière déterminée la prestation d’un montant fixe sans sélection mais avec une augmentation correspondante de la prime ?', '[{"id": "opt-0", "text": "Indexation des prestations", "isCorrect": true}, {"id": "opt-1", "text": "Bonification de couverture automatique", "isCorrect": false}, {"id": "opt-2", "text": "Garantie d’assurabilité future", "isCorrect": false}, {"id": "opt-3", "text": "Garantie d’hospitalisation", "isCorrect": false}]'::jsonb, 28, NOW(), NOW())
  ON CONFLICT DO NOTHING;
