  VALUES ('qbi-accma_supp-0029', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quel avenant correspond aux caractéristiques suivantes : pas de sélection médicale, la perte doit survenir dans les 365 jours, montant forfaitaire.', '[{"id": "opt-0", "text": "Présomption d’invalidité totale", "isCorrect": true}, {"id": "opt-1", "text": "DMA", "isCorrect": false}, {"id": "opt-2", "text": "Garantie d’hospitalisation", "isCorrect": false}, {"id": "opt-3", "text": "Prestation de réhabilitation", "isCorrect": false}]'::jsonb, 29, NOW(), NOW())
  ON CONFLICT DO NOTHING;
