  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0031', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Evelyne a eu un grave accident de ski il y a quelque mois.  Suite à cette période d’invalidité totale, elle retourne au travail à temps partiel la semaine prochaine.  Son salaire à temps partiel sera de 2500$ par mois soit la moitié moins que ce qu’elle gagne habituellement. Elle se demande combien l’assureur lui versera si elle a un avenant d’invalidité résiduelle et un montant de prestation équivalent à 60% de son revenu.', '[{"id": "opt-0", "text": "4500$", "isCorrect": true}, {"id": "opt-1", "text": "3000$", "isCorrect": false}, {"id": "opt-2", "text": "1500$", "isCorrect": false}, {"id": "opt-3", "text": "0$", "isCorrect": false}]'::jsonb, 31, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0032', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Marion a été impliqué dans un grave accident de la route en octobre dernier.  Suite à cet accident, il a été en invalidité totale pendant plusieurs mois.  Il retourne au travail dans quelques jours.  Il travaillera 3 jours par semaine.  Il possède une assurance invalidité qui le couvre à 3200$ par mois et cette assurance possède un avenant d’invalidité résiduelle.  Combien pourra-t-il réclamer ?', '[{"id": "opt-0", "text": "3200$", "isCorrect": true}, {"id": "opt-1", "text": "1280$", "isCorrect": false}, {"id": "opt-2", "text": "1920$", "isCorrect": false}, {"id": "opt-3", "text": "0$", "isCorrect": false}]'::jsonb, 32, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0033', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Bruno est intéressé par votre assurance mais il aimerait bien faire rajouter l’avenant de remboursement des primes.  Que pourriez-vous lui dire sur cet avenant ?', '[{"id": "opt-0", "text": "Qu’il pourra assurément recevoir toutes ses primes même s’il réclame.", "isCorrect": true}, {"id": "opt-1", "text": "Que les remboursements sont imposables", "isCorrect": false}, {"id": "opt-2", "text": "Que l’avenant pourrait faire augmenter sa prime de 40 à 60%", "isCorrect": false}, {"id": "opt-3", "text": "Que cet avenant est très avantageux surtout s’il pense réclamer souvent", "isCorrect": false}]'::jsonb, 33, NOW(), NOW())
  ON CONFLICT DO NOTHING;
