  VALUES ('qbi-accma_supp-0034', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Si le preneur représente un risque supérieur à la moyenne, l’assureur ne pourrait :', '[{"id": "opt-0", "text": "Imposer une surprime", "isCorrect": true}, {"id": "opt-1", "text": "Ajouter un avenant d’exclusion", "isCorrect": false}, {"id": "opt-2", "text": "Refuser sa proposition", "isCorrect": false}, {"id": "opt-3", "text": "Diminuer la prime", "isCorrect": false}, {"id": "opt-4", "text": "La garantie en cas d’hospitalisation :", "isCorrect": false}, {"id": "opt-5", "text": "Couvre l’assuré après le délai de carence de sa police", "isCorrect": false}, {"id": "opt-6", "text": "Donne des prestations mensuelles de 3000$ et plus", "isCorrect": false}, {"id": "opt-7", "text": "Est calculé sur le prorata hebdomadaire de la prestation de base", "isCorrect": false}]'::jsonb, 34, NOW(), NOW())
  ON CONFLICT DO NOTHING;
  INSERT INTO "QuestionBankItem" (id, "tenantId", "bankId", type, question, options, "sortOrder", "createdAt", "updatedAt")
  VALUES ('qbi-accma_supp-0035', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Couvre la période entre la journée d’hospitalisation et le début du versement des prestations.', '[{"id": "opt-0", "text": "En ce qui a trait à l’imposition :", "isCorrect": true}, {"id": "opt-1", "text": "Toute prime payé par l’assuré rend sa prestation imposable", "isCorrect": false}, {"id": "opt-2", "text": "Toute prime payé totalement par l’employeur rend la prestation non-imposable", "isCorrect": false}, {"id": "opt-3", "text": "Toute prime payé par l’employeur et l’employé est non-imposable", "isCorrect": false}, {"id": "opt-4", "text": "Toute prime payé totalement par l’employeur rend la prestation imposable", "isCorrect": false}]'::jsonb, 35, NOW(), NOW())
