  VALUES ('qbi-accma_supp-0036', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Quelle caractéristique ne convient pas pour l’invalidité de courte durée ?', '[{"id": "opt-0", "text": "Prestation de l’ordre de 70 à 75% du revenu avant invalidité", "isCorrect": true}, {"id": "opt-1", "text": "Définition d’invalidité « toute profession »", "isCorrect": false}, {"id": "opt-2", "text": "Durée maximale des prestations : 12 mois", "isCorrect": false}, {"id": "opt-3", "text": "Peut se coordonner avec l’assurance emploi", "isCorrect": false}]'::jsonb, 36, NOW(), NOW())
