  VALUES ('qbi-accma_supp-0039', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Pascal travaille pour un employeur qui offre de l’assurance collective.  Pascal et son employeur se partagent le coût de la prime qui est de 2100$ annuellement.  Ce printemps, Pascal a eu un accident de motoneige et il a réclamé 6500$.  Pascal n’avait pas réclamé depuis 3 ans.  Quelle portion de sa réclamation sera non-imposable ?', '[{"id": "opt-0", "text": "3150$", "isCorrect": true}, {"id": "opt-1", "text": "3350$", "isCorrect": false}, {"id": "opt-2", "text": "1050$", "isCorrect": false}, {"id": "opt-3", "text": "5450$", "isCorrect": false}]'::jsonb, 39, NOW(), NOW())
  ON CONFLICT DO NOTHING;
