  VALUES ('qbi-accma_supp-0040', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Timothée avait souscrit, en 2010, une assurance invalidité individuel alors qu’il gagnait 62000$ par année pour compléter son assurance collective qui lui donne 70% de son revenu. Son assurance invalidité individuelle l’amenait à la limite permise. En 2018, lors d’une restructuration de l’entreprise son revenu a baissé à 48000$ par année.  S’il devait réclamer aujourd’hui, combien recevrait-il de son assurance collective ?', '[{"id": "opt-0", "text": "2625$", "isCorrect": true}, {"id": "opt-1", "text": "775$", "isCorrect": false}, {"id": "opt-2", "text": "3400$", "isCorrect": false}, {"id": "opt-3", "text": "2800$", "isCorrect": false}]'::jsonb, 40, NOW(), NOW())
  ON CONFLICT DO NOTHING;
