  VALUES ('qbi-accma_supp-0042', v_tenant_id, v_bank_id, 'MULTIPLE_CHOICE', 'Sylvia vient d’acheter une police maladie grave.  Si on lui diagnostique un cancer dans deux semaines, qu’est-ce qui l’empêcherait de se faire payer ?', '[{"id": "opt-0", "text": "Le délai de survie", "isCorrect": true}, {"id": "opt-1", "text": "La période d’admissibilité", "isCorrect": false}, {"id": "opt-2", "text": "La pondération de la police", "isCorrect": false}]'::jsonb, 42, NOW(), NOW())
